export async function GET(req: Request) {
  const url = new URL(req.url)
  if (url.searchParams.get('secret') !== 'turbo-seed-2026') {
    return NextResponse.json({ error: 'unauthorized' }, { status: 401 })
  }
  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!
  )
  const slug = 'dogao-do-denis-ikir'
  const { data: biz, error: bizErr } = await supabase.from('businesses').select('*').eq('slug', slug).single()
  if (bizErr || !biz) return NextResponse.json({ error: 'business not found', detail: bizErr?.message }, { status: 404 })

  // upload images
  await supabase.storage.createBucket('menu', { public: true }).catch(()=>{})
  const urls: Record<string,string> = {}
  for (const key of Object.keys(IMAGES)) {
    const buffer = Buffer.from(IMAGES[key], 'base64')
    const path = `${biz.id}/${key}.png`
    await supabase.storage.from('menu').upload(path, buffer, { contentType: 'image/png', upsert: true })
    urls[key] = supabase.storage.from('menu').getPublicUrl(path).data.publicUrl
  }

  // update business config (complete profile)
  await supabase.from('businesses').update({
    description: 'O melhor dogão e hambúrguer artesanal de Campo Grande! Peça pelo WhatsApp e receba quentinho em casa. 🌭🍔',
    city: 'Campo Grande', state: 'MS',
    instagram: 'dogaododenis', whatsapp: biz.whatsapp || '5567999999999',
    primary_color: '#e11d48', secondary_color: '#f97316', theme: 'modern', layout: 'premium',
    show_watermark: false,
    payment_methods: ['Pix','Dinheiro','Cartão de Crédito','Cartão de Débito','Vale Refeição'],
    pix_key: 'contato@dogaododenis.com.br',
    delivery_areas: [
      { name: 'Centro', fee: 5.00 }, { name: 'Jardim dos Estados', fee: 6.00 },
      { name: 'Tiradentes', fee: 7.00 }, { name: 'Coophavila', fee: 8.00 },
      { name: 'Retirada no local', fee: 0 },
    ],
    loyalty_enabled: true, loyalty_goal: 10, loyalty_reward: '1 Dogão Completo grátis',
    opening_hours: {
      monday:{open:'18:00',close:'23:30',closed:false}, tuesday:{open:'18:00',close:'23:30',closed:false},
      wednesday:{open:'18:00',close:'23:30',closed:false}, thursday:{open:'18:00',close:'23:30',closed:false},
      friday:{open:'18:00',close:'00:30',closed:false}, saturday:{open:'18:00',close:'00:30',closed:false},
      sunday:{open:'18:00',close:'23:00',closed:false},
    },
  }).eq('id', biz.id)

  // wipe existing menu
  await supabase.from('products').delete().eq('business_id', biz.id)
  await supabase.from('categories').delete().eq('business_id', biz.id)
  await supabase.from('reviews').delete().eq('business_id', biz.id)

  let catSort = 0, counts = { categories: 0, products: 0 }
  for (const cat of MENU) {
    const [cname, icon, products] = cat
    const { data: catRow } = await supabase.from('categories').insert({
      business_id: biz.id, name: cname, icon, sort_order: catSort++, is_active: true,
    }).select('id').single()
    counts.categories++
    let pSort = 0
    for (const p of products) {
      const [, img, name, desc, price, promo, featured, combo] = p
      await supabase.from('products').insert({
        business_id: biz.id, category_id: catRow?.id ?? null,
        name, description: desc, price, promotional_price: promo,
        image_url: urls[img] ?? null,
        is_available: true, is_featured: featured, is_combo: combo,
        sort_order: pSort++, views: Math.floor(Math.random()*400)+50, orders: Math.floor(Math.random()*120)+5,
      })
      counts.products++
    }
  }

  // reviews
  for (const r of REVIEWS) {
    await supabase.from('reviews').insert({
      business_id: biz.id, customer_name: r[0], rating: r[1], comment: r[2], approved: true,
    })
  }

  // coupon (best-effort)
  let couponsAdded = 0
  try {
    await supabase.from('coupons').delete().eq('business_id', biz.id)
    const { error: cErr } = await supabase.from('coupons').insert([
      { business_id: biz.id, code: 'BEMVINDO10', discount_type: 'percentage', discount_value: 10, is_active: true, min_order_value: 25 },
      { business_id: biz.id, code: 'FRETEGRATIS', discount_type: 'fixed', discount_value: 8, is_active: true, min_order_value: 40 },
    ])
    if (!cErr) couponsAdded = 2
  } catch {}

  return NextResponse.json({ ok: true, ...counts, reviews: REVIEWS.length, coupons: couponsAdded, slug })
}
